511	func writeTryResult(w io.Writer, report agent.ExecuteBeadReport) {
512		fmt.Fprintf(w, "\nbead: %s\nstatus: %s\n", report.BeadID, report.Status)
513		if report.Detail != "" {
514			fmt.Fprintf(w, "detail: %s\n", report.Detail)
515		}
516		if report.ResultRev != "" {
517			fmt.Fprintf(w, "result_rev: %s\n", report.ResultRev)
518		}
519		if report.PreserveRef != "" {
520			fmt.Fprintf(w, "preserve_ref: %s\n", report.PreserveRef)
521		}
522	}
