524	// tryExitCodeForStatus maps a bead execution status string to the ddx try exit code contract.
525	func tryExitCodeForStatus(status string) error {
526		switch status {
527		case agent.ExecuteBeadStatusSuccess, agent.ExecuteBeadStatusAlreadySatisfied:
528			return nil // exit 0
529		case agent.ExecuteBeadStatusPreservedNeedsReview, agent.ExecuteBeadStatusNoChanges,
530			agent.ExecuteBeadStatusNoEvidenceProduced:
531			return &ExitError{Code: tryExitPreservedOrNone, Message: ""}
532		default:
533			// execution_failed and all other terminal non-success statuses
534			return &ExitError{Code: tryExitFailed, Message: ""}
535		}
536	}
