538	// unmetDeps returns the IDs of deps that are not yet closed, in the order
539	// they appear in the bead's dependency list.
540	func unmetDeps(store *bead.Store, b *bead.Bead) []string {
541		depIDs := b.DepIDs()
542		if len(depIDs) == 0 {
543			return nil
544		}
545		var unmet []string
546		for _, depID := range depIDs {
547			dep, err := store.Get(context.Background(), depID)
548			if err != nil || dep.Status != bead.StatusClosed {
549				unmet = append(unmet, depID)
550			}
551		}
552		return unmet
553	}
