555	// singleBeadStore wraps a *bead.Store and overrides ReadyExecution to return
556	// only a single target bead. All other operations are delegated unchanged.
557	// This allows the execute-bead worker to treat the forced bead as if it were
558	// the only entry in the execution-ready queue.
559	type singleBeadStore struct {
560		*bead.Store
561		target bead.Bead
562	}
563	
564	func (s *singleBeadStore) ReadyExecution() ([]bead.Bead, error) {
565		return []bead.Bead{s.target}, nil
566	}

