1406	// TestApplyLandResult_PreservesImplementationRevAndSetsLandedRev verifies that
1407	// a successful land preserves the worker's own commit as ImplementationRev and
1408	// records the target branch tip as LandedRev, without losing the original rev.
1409	func TestApplyLandResult_PreservesImplementationRevAndSetsLandedRev(t *testing.T) {
1410		const workerSHA = "aaaa1111bbbb2222cccc3333dddd4444eeee5555"
1411		const branchTip = "ffff6666aaaa7777bbbb8888cccc9999dddd0000"
1412	
1413		res := &ExecuteBeadResult{
1414			BeadID:    "ddx-test",
1415			BaseRev:   "0000000000000000000000000000000000000000",
1416			ResultRev: workerSHA,
1417		}
1418		land := &LandResult{
1419			Status: "landed",
1420			NewTip: branchTip,
1421			Merged: false,
1422		}
1423	
1424		ApplyLandResultToExecuteBeadResult(res, land)
1425	
1426		if res.ImplementationRev != workerSHA {
1427			t.Errorf("ImplementationRev: want %q, got %q", workerSHA, res.ImplementationRev)
1428		}
1429		if res.LandedRev != branchTip {
1430			t.Errorf("LandedRev: want %q, got %q", branchTip, res.LandedRev)
1431		}
1432		// ResultRev is the backwards-compat alias that mirrors LandedRev.
1433		if res.ResultRev != branchTip {
1434			t.Errorf("ResultRev (compat): want %q, got %q", branchTip, res.ResultRev)
1435		}
1436		// Outcome must be "merged".
1437		if res.Outcome != "merged" {
1438			t.Errorf("Outcome: want %q, got %q", "merged", res.Outcome)
1439		}
1440	}
