13	// FindProjectRoot walks up from startDir to find the git repository root.
14	// It returns the top-level directory of the git working tree. If startDir
15	// is not inside a git repository, it returns startDir unchanged.
16	//
17	// This is analogous to `git rev-parse --show-toplevel` and ensures that
18	// ddx always operates from the repository root regardless of the caller's
19	// working directory. Without this, running `ddx` from a subdirectory that
20	// contains its own `.ddx/` folder would silently use the wrong workspace.
21	func FindProjectRoot(startDir string) string {
22		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
23		defer cancel()
24	
25		cmd := Command(ctx, startDir, "rev-parse", "--show-toplevel")
26		out, err := cmd.Output()
27		if err != nil {
28			// Not in a git repo — fall back to the original directory.
29			return startDir
30		}
31		root := strings.TrimSpace(string(out))
32		if root == "" {
33			return startDir
34		}
35		if physical := physicalGitRoot(startDir); physical != "" && !samePath(physical, root) {
36			return physical
37		}
38		return root
39	}
40	
41	// physicalGitRoot walks upward on disk until it finds a .git directory or
42	// linked-worktree .git file. This intentionally bypasses git's configured
43	// worktree resolution so a corrupted local core.worktree cannot redirect ddx
44	// away from the checkout the operator actually invoked.
45	func physicalGitRoot(startDir string) string {
46		current, err := filepath.Abs(startDir)
47		if err != nil {
48			return ""
49		}
50		for {
51			if _, statErr := os.Stat(filepath.Join(current, ".git")); statErr == nil {
52				return current
53			}
54			parent := filepath.Dir(current)
55			if parent == current {
56				return ""
57			}
58			current = parent
59		}
60	}
